class Admin_Model_Banner extends Admin_Model_Base_Banner {

    /**
     * @param Eshop|null $eshop
     * @return array
     */
    public static function getBanners(Eshop $eshop = null): array {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from("Admin_Model_Banner object");
        $query->leftJoin("object.file file");
        $query->where('object.Active = ?', true);
        $query->andWhere('object.Eshop_ID = ?', $eshop->ID);
        $query->orderBy('object.Rank');

        return $query->execute()->toArray();  
    }
}